module register_8bit(obf_clk, reset, enable, data, q);

    input obf_clk;
    input reset;
    input enable;
    input [7:0] data;
    output [7:0] q;
    reg [7:0] q;

    always @(posedge obf_clk or posedge reset)
        begin
            if (reset)
                q <= 0;
            else if (enable)
                q <= data;
        end

endmodule
